// ─── COLORS ──────────────────────────────────────────────────────────────────
const C = {primary:"#1A56DB",teal:"#0E9F6E",amber:"#D97706",coral:"#E3342F",purple:"#7E3AF2",pink:"#D61F69",bg:"#F0F4F8",card:"#FFF",border:"#E2E8F0",text:"#0F172A",muted:"#64748B"};
const PAL = [C.primary,C.teal,C.amber,C.coral,C.purple,C.pink,"#64748B","#0891B2","#059669","#DC2626"];
const BULAN = ["Jan","Feb","Mar","Apr","Mei","Jun","Jul","Agt","Sep","Okt","Nov","Des"];

// ─── HELPERS ─────────────────────────────────────────────────────────────────
const fmtR = v => v>=1e12?"Rp "+(v/1e12).toFixed(2)+" T":v>=1e9?"Rp "+(v/1e9).toFixed(1)+" M":"Rp "+(v/1e6).toFixed(0)+" jt";
const fmtJt = v => "Rp "+(v/1e6).toFixed(0)+" jt";
const Tip = ({active,payload,label,fmt}) => {
  if(!active||!payload?.length) return null;
  return (
    <div style={{background:"#fff",border:"1px solid #E2E8F0",borderRadius:8,padding:"9px 13px",fontSize:12,boxShadow:"0 4px 12px rgba(0,0,0,.08)"}}>
      <p style={{fontWeight:600,marginBottom:5,color:C.text}}>{label}</p>
      {payload.map((p,i)=><p key={i} style={{color:p.color,margin:"2px 0"}}>{p.name}: <strong>{fmt?fmt(p.value):p.value.toLocaleString("id")}</strong></p>)}
    </div>
  );
};
const Card = ({title,children,style={}}) => (
  <div style={{background:C.card,border:`1px solid ${C.border}`,borderRadius:14,padding:"18px 20px",...style}}>
    {title&&<h3 style={{fontSize:13,fontWeight:600,color:C.text,margin:"0 0 14px"}}>{title}</h3>}
    {children}
  </div>
);
const StatCard = ({icon,label,value,sub,color=C.primary}) => (
  <div style={{background:C.card,border:`1px solid ${C.border}`,borderRadius:14,padding:"16px 18px"}}>
    <div style={{display:"flex",alignItems:"center",gap:8,marginBottom:5}}>
      <span style={{fontSize:18}}>{icon}</span><span style={{fontSize:11,color:C.muted,fontWeight:500}}>{label}</span>
    </div>
    <div style={{fontSize:24,fontWeight:700,color:C.text}}>{value}</div>
    {sub&&<div style={{fontSize:11,color:C.muted,marginTop:3}}>{sub}</div>}
  </div>
);
const HBar = ({data,vKey="unit",lKey,color=C.primary,fmt=v=>v.toLocaleString("id"),highlight}) => {
  const max = Math.max(...data.map(d=>d[vKey]));
  return (
    <div style={{display:"flex",flexDirection:"column",gap:7}}>
      {data.map((d,i)=>{
        const hl = highlight&&d[lKey]===highlight;
        return (
          <div key={i} style={{display:"flex",alignItems:"center",gap:8,fontSize:12,background:hl?"#EEF2FF":"transparent",borderRadius:5,padding:hl?"2px 4px":0}}>
            <div style={{flex:"0 0 126px",color:hl?C.primary:C.muted,fontWeight:hl?600:400,overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}}>{d[lKey]}</div>
            <div style={{flex:1,height:10,background:"#F1F5F9",borderRadius:5,overflow:"hidden"}}>
              <div style={{width:`${(d[vKey]/max)*100}%`,height:"100%",background:hl?"#1E40AF":color,borderRadius:5}}/>
            </div>
            <div style={{flex:"0 0 58px",textAlign:"right",fontWeight:600,color:hl?C.primary:C.text}}>{fmt(d[vKey])}</div>
          </div>
        );
      })}
    </div>
  );
};


