// Lookup helper: by cc (kode6)
function getKecStats(cc) {
  return KEC_STATS[cc] || null;
}

// Get perumahan list by cc code
function getPerumahan(cc) {
  const s = KEC_STATS[cc];
  return s ? s.peru : [];
}

// Get jumlah perumahan by cc
function getJumlahPerumahan(cc) {
  const s = KEC_STATS[cc];
  return s ? s.jp : 0;
}


