function MapKec({kabName, metric}) {
  const [tooltip, setTooltip] = useState(null);

  const gadmKab = KAB_NAME_MAP[kabName] || "";
  // Enrich kecList with real data from KEC_STATS (overrides hardcoded KEC_PATHS values)
  const kecList = useMemo(()=>KEC_PATHS.filter(k=>k.kab===gadmKab).map(k=>{
    const s = KEC_STATS[k.cc];
    return s ? {...k, unit:s.unit, nilai:s.nilai} : k;
  }),[gadmKab]);

  const maxVal = useMemo(()=>Math.max(1,...kecList.map(k=>metric==="unit"?k.unit:k.nilai)),[kecList,metric]);

  const {vb,vbX,vbY,vbW,vbH} = useMemo(()=>{
    if(!kecList.length) return {vb:`0 0 ${SVG_W} ${SVG_H}`,vbX:0,vbY:0,vbW:SVG_W,vbH:SVG_H};
    let minX=Infinity,maxX=-Infinity,minY=Infinity,maxY=-Infinity;
    kecList.forEach(k=>{
      const nums=(k.d.match(/-?\d+/g)||[]);
      for(let i=0;i<nums.length-1;i+=2){
        const x=+nums[i],y=+nums[i+1];
        if(x<minX)minX=x; if(x>maxX)maxX=x;
        if(y<minY)minY=y; if(y>maxY)maxY=y;
      }
    });
    const pad=120;
    const x=minX-pad,y=minY-pad,w=maxX-minX+2*pad,h=maxY-minY+2*pad;
    return {vb:`${x} ${y} ${w} ${h}`,vbX:x,vbY:y,vbW:w,vbH:h};
  },[kecList]);

  const fs = Math.max(18, Math.round(vbW/32));

  if(!kecList.length) return (
    <div style={{padding:"40px",textAlign:"center",color:"#64748B",background:"#F8FAFC",borderRadius:10}}>
      <div style={{fontSize:32,marginBottom:12}}>🗺️</div>
      <div>Data kecamatan tidak tersedia untuk <strong>{kabName}</strong></div>
    </div>
  );

  const fmtV = v => v>=1e12?"Rp "+(v/1e12).toFixed(2)+"T":v>=1e9?"Rp "+(v/1e9).toFixed(1)+"M":"Rp "+(v/1e6).toFixed(0)+"jt";

  // Sort kecamatan by unit descending for legend
  const sortedForLegend = useMemo(()=>[...kecList].sort((a,b)=>(metric==="unit"?b.unit-a.unit:b.nilai-a.nilai)),[kecList,metric]);

  // Assign rank color (top5 get distinct colors, rest choropleth)
  const TOP_COLORS = ["#1D4ED8","#0891B2","#059669","#D97706","#DC2626"];

  return (
    <div style={{display:"flex",flexDirection:"column",width:"100%"}}>
      <div style={{position:"relative",width:"100%"}}>
        <svg viewBox={vb} width="100%" style={{display:"block",borderRadius:10}}>
          <rect x={vbX} y={vbY} width={vbW} height={vbH} fill="#DBEAFE"/>
          {kecList.map(k=>{
            const val=metric==="unit"?k.unit:k.nilai;
            const rankIdx=sortedForLegend.findIndex(s=>s.cc===k.cc&&s.name===k.name);
            const t=val>0?Math.pow(val/maxVal,0.42):0;
            const fill=val>0?(rankIdx<5?TOP_COLORS[rankIdx]:`rgb(${Math.round(219-t*175)},${Math.round(234-t*165)},${Math.round(254-t*80)})`):"#E8F1FE";
            return (
              <path key={k.cc+k.name} d={k.d} fill={fill}
                stroke="#fff" strokeWidth={Math.max(1.5,vbW/400)}
                style={{cursor:"pointer",transition:"fill .15s"}}
                onMouseEnter={()=>setTooltip({x:k.cx,y:k.cy,cc:k.cc,name:k.name,unit:k.unit,nilai:k.nilai,rank:rankIdx+1,color:rankIdx<5?TOP_COLORS[rankIdx]:"#93C5FD"})}
                onMouseLeave={()=>setTooltip(null)}/>
            );
          })}
          {tooltip&&(()=>{
            const pw=fs*22;
            const stats=getKecStats(tooltip.cc);
            const perumahanList=stats?stats.peru:[];
            const jpCount=stats?stats.jp:0;
            const ph=fs*(perumahanList.length>0?10.5:8);
            const tx=tooltip.x+fs*1.5>vbX+vbW-pw?tooltip.x-pw-fs:tooltip.x+fs*1.5;
            const ty=Math.max(vbY+fs,Math.min(tooltip.y-ph/2,vbY+vbH-ph));
            return (
              <g transform={`translate(${tx},${ty})`}>
                <rect width={pw} height={ph} rx={fs*0.8} fill="#0F172A" fillOpacity={.96}/>
                <rect x={0} y={0} width={fs*0.8} height={ph} rx={fs*0.3} fill={tooltip.color}/>
                <text x={fs*1.3} y={fs*1.8} fontSize={fs*1.1} fontWeight="700" fill={tooltip.color}>{tooltip.name}</text>
                <text x={fs*1.3} y={fs*3.3} fontSize={fs*0.95} fill="#FCD34D">🏠 Unit: {tooltip.unit.toLocaleString("id")}</text>
                <text x={fs*1.3} y={fs*4.7} fontSize={fs*0.95} fill="#6EE7B7">💰 FLPP: {fmtV(tooltip.nilai)}</text>
                {jpCount>0&&<text x={fs*1.3} y={fs*6.1} fontSize={fs*0.88} fill="#93C5FD">🏘️ {jpCount} perumahan</text>}
                {perumahanList.length>0&&<text x={fs*1.3} y={fs*7.3} fontSize={fs*0.82} fill="#94A3B8">Top perumahan:</text>}
                {perumahanList.slice(0,3).map((p,i)=>(
                  <text key={i} x={fs*2} y={fs*(8.4+i*1.15)} fontSize={fs*0.8} fill="#E2E8F0">· {p.length>28?p.slice(0,27)+"…":p}</text>
                ))}
              </g>
            );
          })()}
          <defs><linearGradient id="lgKec" x1="0" x2="1"><stop offset="0%" stopColor="#BFDBFE"/><stop offset="100%" stopColor="#1E3A8A"/></linearGradient></defs>
          {/* Gradient legend for non-top areas */}
          <rect x={vbX+fs*0.5} y={vbY+vbH-fs*4.5} width={fs*14} height={fs*4} rx={fs*0.5} fill="rgba(255,255,255,.92)" stroke="#CBD5E1" strokeWidth={1}/>
          <text x={vbX+fs*1} y={vbY+vbH-fs*2.8} fontSize={fs*0.82} fontWeight="600" fill="#334155">Skala {metric==="unit"?"Unit":"Nilai"}</text>
          <rect x={vbX+fs*1} y={vbY+vbH-fs*2.0} width={fs*12} height={fs*1.1} rx={fs*0.2} fill="url(#lgKec)"/>
          <text x={vbX+fs*1} y={vbY+vbH-fs*0.5} fontSize={fs*0.75} fill="#64748B">Rendah</text>
          <text x={vbX+fs*13} y={vbY+vbH-fs*0.5} fontSize={fs*0.75} fill="#64748B" textAnchor="end">Tinggi</text>
        </svg>
      </div>
      {/* Legend panel below map */}
      <div style={{padding:"10px 12px",background:"#F8FAFC",borderTop:"1px solid #E2E8F0",borderRadius:"0 0 10px 10px"}}>
        <div style={{fontSize:11,fontWeight:600,color:"#475569",marginBottom:6}}>🏆 Top Kecamatan</div>
        <div style={{display:"flex",flexWrap:"wrap",gap:"6px 14px"}}>
          {sortedForLegend.slice(0,5).map((k,i)=>(
            <div key={k.cc+k.name} style={{display:"flex",alignItems:"center",gap:5,fontSize:10.5}}>
              <div style={{width:12,height:12,borderRadius:3,background:TOP_COLORS[i],flexShrink:0}}/>
              <span style={{color:"#334155",fontWeight:500}}>{i+1}. {k.name}</span>
              <span style={{color:"#64748B"}}>({(metric==="unit"?k.unit:k.nilai).toLocaleString("id")}{metric==="unit"?" unit":""})</span>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
}


// ─── CHOROPLETH COLOR ────────────────────────────────────────────────────────
function mapColor(val, max) {
  if(!val||max===0) return "#E8F1FE";
  const t = Math.pow(val/max, 0.42);
  return `rgb(${Math.round(219-t*175)},${Math.round(234-t*165)},${Math.round(254-t*80)})`;
}

// ─── CHOROPLETH MAP COMPONENT ────────────────────────────────────────────────
function MapKab({metric, selected, onSelect}) {
  const [tooltip, setTooltip] = useState(null);
  const dataMap = useMemo(()=>Object.fromEntries(KAB_DATA.map(d=>[d.name,d])),[]);
  const maxVal = useMemo(()=>Math.max(...KAB_DATA.map(d=>d[metric])),[metric]);

  return (
    <div style={{position:"relative",width:"100%"}}>
      <svg viewBox={`0 0 ${SVG_W} ${SVG_H}`} width="100%" style={{display:"block",borderRadius:10}}>
        {/* Ocean */}
        <rect width={SVG_W} height={SVG_H} fill="#DBEAFE" rx="8"/>
        {/* Paths */}
        {JABAR_PATHS.map(p=>{
          const rec = dataMap[p.name];
          const val = rec?.[metric]??0;
          const isSel = selected===p.name;
          const isKota = p.type==="Kota";
          return (
            <path key={p.name} d={p.d}
              fill={isSel ? "#FDE68A" : mapColor(val, maxVal)}
              stroke={isSel?"#92400E":isKota?"#6366F1":"#94A3B8"}
              strokeWidth={isSel?2:isKota?0.9:0.5}
              strokeLinejoin="round"
              style={{cursor:"pointer",transition:"fill .18s"}}
              onClick={()=>onSelect(isSel?null:p.name)}
              onMouseEnter={()=>{
                if(!selected) setTooltip({x:p.cx,y:p.cy,name:p.name,type:p.type,unit:rec?.unit??0,nilai:rec?.nilai_flpp??0});
              }}
              onMouseLeave={()=>setTooltip(null)}
            />
          );
        })}
        {/* Labels — scaled 4x for higher resolution SVG space */}
        {JABAR_PATHS.map(p=>{
          const rec = dataMap[p.name];
          if(!rec||rec.unit<4000) return null;
          const short = p.name.replace("Kab. ","").replace("Kota ","").split(" ")[0];
          return (
            <text key={p.name+"_l"} x={p.cx} y={p.cy+12}
              textAnchor="middle" fontSize={p.type==="Kota"?28:34}
              fill="#1e3a5f" fontWeight="600"
              style={{pointerEvents:"none",userSelect:"none",filter:"drop-shadow(0 0 8px white) drop-shadow(0 0 4px white)"}}>
              {short}
            </text>
          );
        })}
        {/* Color legend bar — scaled 4x */}
        <g transform={`translate(56,${SVG_H-168})`}>
          <rect width={680} height={144} rx={24} fill="rgba(255,255,255,.92)" stroke="#CBD5E1" strokeWidth={2}/>
          <text x={32} y={52} fontSize={36} fontWeight={600} fill="#334155">
            {metric==="unit"?"Jumlah Unit Akad":"Nilai FLPP"}
          </text>
          <defs>
            <linearGradient id="lg" x1="0" x2="1" y1="0" y2="0">
              <stop offset="0%" stopColor="#DBEAFE"/>
              <stop offset="100%" stopColor="#1E3A8A"/>
            </linearGradient>
          </defs>
          <rect x={32} y={72} width={480} height={40} rx={12} fill="url(#lg)" stroke="#CBD5E1" strokeWidth={1.2}/>
          <text x={32} y={136} fontSize={32} fill="#64748B">Rendah</text>
          <text x={512} y={136} fontSize={32} fill="#64748B" textAnchor="end">Tinggi</text>
        </g>
        {/* Compass — scaled 4x */}
        <g transform={`translate(${SVG_W-120},112)`}>
          <circle r={52} fill="white" fillOpacity={.92} stroke="#CBD5E1" strokeWidth={2.4}/>
          <text x={0} y={-4} textAnchor="middle" fontSize={36} fill="#334155" fontWeight="700">N</text>
          <polygon points="0,-40 10,-12 0,-24 -10,-12" fill="#334155"/>
        </g>
        {/* Kota legend — scaled 4x */}
        <g transform={`translate(${SVG_W-420},${SVG_H-100})`}>
          <rect width={400} height={80} rx={16} fill="rgba(255,255,255,.88)" stroke="#CBD5E1" strokeWidth={1.6}/>
          <line x1={28} y1={40} x2={80} y2={40} stroke="#6366F1" strokeWidth={4.8}/>
          <text x={100} y={56} fontSize={32} fill="#475569">= batas Kota</text>
        </g>
        {/* SVG tooltip — scaled 4x */}
        {tooltip&&(
          <g transform={`translate(${Math.min(tooltip.x+40,SVG_W-700)},${Math.max(tooltip.y-320,32)})`}>
            <rect width={660} height={320} rx={32} fill="#0F172A" fillOpacity={.94}/>
            <text x={40} y={80} fontSize={44} fontWeight="700" fill="#93C5FD">{tooltip.name}</text>
            <text x={40} y={130} fontSize={36} fill="#94A3B8">{tooltip.type}</text>
            <text x={40} y={195} fontSize={38} fill="#E2E8F0">Unit: <tspan fontWeight="700" fill="#FCD34D">{tooltip.unit.toLocaleString("id")}</tspan></text>
            <text x={40} y={255} fontSize={38} fill="#E2E8F0">FLPP: <tspan fontWeight="700" fill="#6EE7B7">{fmtR(tooltip.nilai)}</tspan></text>
            <text x={40} y={305} fontSize={30} fill="#64748B">Share: {((tooltip.unit/295008)*100).toFixed(2)}%</text>
          </g>
        )}
      </svg>
    </div>
  );
}

