  const TABS=[{id:"ringkasan",label:"📊 Ringkasan"},{id:"tren",label:"📈 Tren Waktu"},{id:"wilayah",label:"🗺️ Wilayah & Peta"},{id:"bank",label:"🏦 Bank Penyalur"},{id:"debitur",label:"👤 Profil Debitur"}];
  const fyearly = yr==="semua"?YEARLY:YEARLY.filter(d=>d.tahun===+yr);
  const totalUnit = fyearly.reduce((s,d)=>s+d.unit,0);
  const totalFlpp = fyearly.reduce((s,d)=>s+d.nilai_flpp,0);
  const avgHarga = fyearly.reduce((s,d)=>s+d.avg_harga*d.unit,0)/totalUnit;

  const monthlyData = useMemo(()=>{
    const src=yr==="semua"?MONTHLY_RAW:MONTHLY_RAW.filter(d=>d.tahun===+yr);
    const m={};
    src.forEach(d=>{if(!m[d.bulan])m[d.bulan]={bulan:d.bulan,label:BULAN[d.bulan-1],unit:0};m[d.bulan].unit+=d.unit;});
    return Object.values(m).sort((a,b)=>a.bulan-b.bulan);
  },[yr]);

  const bankData = useMemo(()=>yr==="semua"?BANK_ALL:BANK_YEARLY[+yr]?.map(b=>({bank:b.bank,unit:b.unit,nilai_flpp:0}))||[],[yr]);
  const selData = selKab?KAB_DATA.find(d=>d.name===selKab):null;

